# Создание клавиатуры с авторами (для нового сообщения)
def get_authors_keyboard_for_new_message():
    keyboard = []
    # Разбиваем авторов на ряды по 2 кнопки (исключая философов)
    poet_authors = [author for author in AUTHORS if author != "философы"]
    for i in range(0, len(poet_authors), 2):
        row = []
        # Первая кнопка в ряду
        row.append(InlineKeyboardButton(
            POEMS[poet_authors[i]]["name"], 
            callback_data=f'author_{poet_authors[i]}'
        ))
        # Вторая кнопка в ряду (если есть)
        if i + 1 < len(poet_authors):
            row.append(InlineKeyboardButton(
                POEMS[poet_authors[i + 1]]["name"], 
                callback_data=f'author_{poet_authors[i + 1]}'
            ))
        keyboard.append(row)
    
    # Добавляем кнопку "Назад в главное меню"
    keyboard.append([InlineKeyboardButton("🏠 Главное меню", callback_data='main_menu')])
    
    return InlineKeyboardMarkup(keyboard)

# Функция для создания клавиатуры в зависимости от контекста
def get_keyboard_for_author(author_key, context_type='author'):
    """
    Создает клавиатуру для стихов автора.
    context_type может быть:
    - 'author' - при выборе конкретного автора (показывает кнопку "Ещё этого автора")
    - 'random' - при случайном выборе (показывает кнопку "Ещё случайное")
    """
    # Словарь ссылок на видео для разных авторов
    video_links = {
        "слуцкий": "https://youtu.be/Lm1vKgGF-g8?si=CclDhS2ojNjTDYa6",
        "елагин": "https://youtu.be/M8ubtosQs4o?si=wRBXQhp_g2SBZxJs",
        # Милетская школа
        "фалес": "https://youtu.be/lt88jY2ljtY?si=DnK6u9ZUGX-l7776",
        "анаксимандр": "https://youtu.be/lt88jY2ljtY?si=DnK6u9ZUGX-l7776",
        "анаксимен": "https://youtu.be/lt88jY2ljtY?si=DnK6u9ZUGX-l7776"
    }
    
    # Базовая клавиатура
    keyboard = []
    
    # Добавляем кнопку видео, если есть
    if author_key in video_links:
        video_url = video_links[author_key]
        # Получаем имя автора из POEMS
        if author_key in POEMS:
            author_name = POEMS[author_key]["name"]
            button_text = f"🎬 {author_name} (видео)"
        else:
            button_text = "🎬 Видео о философе"
        keyboard.append([InlineKeyboardButton(button_text, url=video_url)])
    
    # Добавляем основную кнопку в зависимости от контекста
    if context_type == 'author':
        keyboard.append([InlineKeyboardButton("🔄 Ещё этого автора", callback_data=f'author_{author_key}')])
    else:  # context_type == 'random'
        keyboard.append([InlineKeyboardButton("🎲 Ещё случайное", callback_data='random')])
    
    # Добавляем остальные кнопки
    keyboard.append([InlineKeyboardButton("📚 Список авторов", callback_data='authors')])
    keyboard.append([InlineKeyboardButton("🏠 Главное меню", callback_data='main_menu')])
    
    return InlineKeyboardMarkup(keyboard)

# Функция для получения случайного стихотворения без повторений
def get_random_poem(author_key, context, chat_id):
    """
    Возвращает случайное стихотворение автора, которое еще не показывалось пользователю
    """
    author_info = POEMS[author_key]
    poems_list = author_info["poems"]
    
    # Создаем ключ для хранения истории просмотров в context.user_data
    # Используем chat_id для разделения истории по разным пользователям
    history_key = f'poems_history_{author_key}_{chat_id}'
    
    # Получаем историю просмотренных стихов для этого автора
    if history_key not in context.user_data:
        context.user_data[history_key] = []
    
    history = context.user_data[history_key]
    
    # Если все стихи уже были показаны, сбрасываем историю
    if len(history) >= len(poems_list):
        context.user_data[history_key] = []
        history = []
    
    # Находим стихи, которые еще не показывались
    available_poems = []
    for i, poem in enumerate(poems_list):
        if i not in history:
            available_poems.append((i, poem))
    
    # Выбираем случайный стих из доступных
    if available_poems:
        poem_index, poem = random.choice(available_poems)
        # Добавляем индекс в историю
        context.user_data[history_key].append(poem_index)
        return poem
    else:
        # Если по какой-то причине нет доступных стихов, берем случайный
        poem = random.choice(poems_list)
        return poem

# Функция для получения случайного автора без повторений (для кнопки random)
def get_random_author_with_history(context, chat_id):
    """
    Возвращает случайного автора, учитывая историю показов
    """
    # Список авторов-поэтов (исключая философов)
    poet_authors = [author for author in AUTHORS if author != "философы"]
    
    # Ключ для хранения истории авторов
    author_history_key = f'random_author_history_{chat_id}'
    
    # Получаем историю
    if author_history_key not in context.user_data:
        context.user_data[author_history_key] = []
    
    history = context.user_data[author_history_key]
    
    # Если все авторы были показаны, сбрасываем историю
    if len(history) >= len(poet_authors):
        context.user_data[author_history_key] = []
        history = []
    
    # Находим авторов, которые еще не показывались
    available_authors = []
    author_indices = {}
    
    for i, author in enumerate(poet_authors):
        if i not in history:
            available_authors.append(author)
            author_indices[author] = i
    
    # Выбираем случайного автора из доступных
    if available_authors:
        selected_author = random.choice(available_authors)
        # Добавляем индекс в историю
        context.user_data[author_history_key].append(author_indices[selected_author])
        return selected_author
    else:
        # Если по какой-то причине нет доступных авторов, берем случайного
        return random.choice(poet_authors)

# Функция для создания клавиатуры с кнопками для авторов, у которых есть видео
